import { Component, Event, EventEmitter, h, Prop } from '@stencil/core';

export type CarouselCardActionType = 'add' | 'favorite';

@Component({
  tag: 'wdpr-carousel-card',
  shadow: true,
})
export class WdprCarouselCard {
  @Prop() src: string;
  @Prop({ attribute: 'a11y-alt' }) a11yAlt: string;
  @Prop() actionType?: CarouselCardActionType;

  @Prop() primaryHeadline: string;
  @Prop() headlineLabel: string;
  @Prop() body: string;

  @Prop() secondaryLabel: string;
  @Prop() secondaryContent: string;

  @Event() wdprFavoritesToggle: EventEmitter<void>;
  @Event() wdprAddToggle: EventEmitter<void>;

  private _handleFavoritesToggle = () => {
    this.wdprFavoritesToggle.emit();
  };

  private _handleAddToggle = () => {
    this.wdprAddToggle.emit();
  };

  private _renderAction() {
    if (this.actionType == null) return null;
    if (this.actionType === 'add') {
      return (
        <wdpr-add-button
          slot="action-button"
          a11yLabel="Add"
          onWdprAddToggle={this._handleAddToggle}
        />
      );
    }
    if (this.actionType === 'favorite') {
      return (
        <wdpr-favorites-button
          slot="action-button"
          ariaLabel="Add to favorites"
          onWdprFavoritesToggle={this._handleFavoritesToggle}
        />
      );
    }
  }

  render() {
    return (
      <article class={wrapperClasses}>
        <div class={actionsWrapperClasses}>
          <slot name="action-button" />
          {this._renderAction()}
        </div>
        <figure class="w-full">
          <wdpr-media src={this.src} alt={this.a11yAlt} aspect="landscape" objectFit="cover" landscapeRatio="4:3" />
        </figure>
        <div class={contentWrapperClasses}>
          <div class="flex flex-col items-start self-stretch gap-200">
            <div class="flex flex-col items-start self-stretch gap-125">
              <div class="flex flex-col items-start self-stretch gap-100">
                <slot name="badge" />
                <div class="flex flex-col items-start self-stretch gap-050">
                  {this.headlineLabel && <span class={headlineLabelClasses}>{this.headlineLabel}</span>}
                  {this.primaryHeadline && <span class={primaryHeadlineClasses}>{this.primaryHeadline}</span>}
                  {this.body && <p class={bodyClasses}>{this.body}</p>}
                </div>
              </div>
              {this.secondaryContent && <div class={secondaryContentClasses}>{this.secondaryContent}</div>}
            </div>
            {this.secondaryLabel && (
              <div class={secondaryLabelWrapperClasses}>
                <slot name="secondary-label-icon" />
                <span class={secondaryLabelClasses}>{this.secondaryLabel}</span>
              </div>
            )}
          </div>
        </div>
        <footer class="flex flex-col w-full">
          <slot name="footer" />
        </footer>
      </article>
    );
  }
}

const wrapperClasses = `flex flex-col items-start self-stretch elevation-small-soft lg:elevation-medium-soft
  rounded-200 relative overflow-hidden w-full`;
const actionsWrapperClasses = 'absolute top-150 right-150 z-10';
const contentWrapperClasses = 'flex flex-col items-start self-stretch p-200';
const headlineLabelClasses = 'text-text-disclaimer label-small line-clamp-1';
const primaryHeadlineClasses = `text-text-heading text-heading-xsmall font-heading-alt leading-heading-xsmall tracking--05 line-clamp-3
  md:text-heading-small md:leading-heading-small
  lg:text-heading-medium lg:leading-heading-medium
  xl:text-heading-large xl:leading-heading-large`;
const bodyClasses = 'text-text-body body-medium line-clamp-5';
const secondaryContentClasses = 'text-text-disclaimer body-small line-clamp-1';
const secondaryLabelWrapperClasses = 'flex items-start gap-050 self-stretch text-text-body';
const secondaryLabelClasses = 'label-small line-clamp-3';
